// Agrupar tareas vencidas por persona asignada
const items = $input.all();
const today = new Date();
today.setHours(0, 0, 0, 0);

const grouped = {};

for (const item of items) {
  const props = item.json.properties || item.json;

  // Extraer nombre del asignado
  let asignado = 'Sin asignar';
  let asignadoEmail = '';
  if (props.Asignado && props.Asignado.people && props.Asignado.people.length > 0) {
    asignado = props.Asignado.people[0].name || 'Sin asignar';
    asignadoEmail = props.Asignado.people[0].person?.email || '';
  }

  // Extraer nombre de la tarea
  let taskName = 'Sin nombre';
  if (props.Name && props.Name.title && props.Name.title.length > 0) {
    taskName = props.Name.title.map(t => t.plain_text).join('');
  } else if (props.Nombre && props.Nombre.title && props.Nombre.title.length > 0) {
    taskName = props.Nombre.title.map(t => t.plain_text).join('');
  }

  // Extraer fecha limite
  let fechaLimite = null;
  let fechaLimiteStr = '';
  let daysOverdue = 0;
  if (props.fecha_limite && props.fecha_limite.date) {
    fechaLimiteStr = props.fecha_limite.date.start || '';
    fechaLimite = new Date(fechaLimiteStr);
    fechaLimite.setHours(0, 0, 0, 0);
    daysOverdue = Math.floor((today - fechaLimite) / (1000 * 60 * 60 * 24));
  }

  // Extraer prioridad
  let prioridad = 'Sin prioridad';
  if (props.Prioridad && props.Prioridad.select) {
    prioridad = props.Prioridad.select.name || 'Sin prioridad';
  } else if (props.prioridad && props.prioridad.select) {
    prioridad = props.prioridad.select.name || 'Sin prioridad';
  }

  // Extraer estado
  let estado = '';
  if (props.estado && props.estado.select) {
    estado = props.estado.select.name || '';
  } else if (props.Estado && props.Estado.select) {
    estado = props.Estado.select.name || '';
  }

  // Extraer URL de la tarea en Notion
  const taskUrl = item.json.url || '';

  const task = {
    taskName,
    fechaLimiteStr,
    daysOverdue,
    prioridad,
    estado,
    taskUrl
  };

  const key = asignadoEmail || asignado;
  if (!grouped[key]) {
    grouped[key] = {
      asignado,
      asignadoEmail,
      tasks: []
    };
  }
  grouped[key].tasks.push(task);
}

// Convertir a array de items para n8n
const result = Object.values(grouped).map(group => {
  // Ordenar tareas por dias de atraso (mayor primero)
  group.tasks.sort((a, b) => b.daysOverdue - a.daysOverdue);
  return {
    json: {
      asignado: group.asignado,
      asignadoEmail: group.asignadoEmail,
      totalTareas: group.tasks.length,
      tasks: group.tasks,
      hasCritical: group.tasks.some(t => t.daysOverdue > 3)
    }
  };
});

return result;

// Construir email HTML personalizado para cada responsable
const item = $input.first().json;
const asignado = item.asignado;
const tasks = item.tasks;
const totalTareas = item.totalTareas;

// Construir filas de la tabla de tareas
let tableRows = '';
for (const task of tasks) {
  const priorityColor = {
    'Alta': '#dc3545',
    'Media': '#fd7e14',
    'Baja': '#28a745',
    'Urgente': '#721c24',
    'Critica': '#721c24'
  }[task.prioridad] || '#6c757d';

  const daysColor = task.daysOverdue > 3 ? '#dc3545' : (task.daysOverdue > 1 ? '#fd7e14' : '#333');

  const taskLink = task.taskUrl
    ? `<a href="${task.taskUrl}" style="color:#0366d6;text-decoration:none;">${task.taskName}</a>`
    : task.taskName;

  tableRows += `
    <tr>
      <td style="padding:10px 12px;border-bottom:1px solid #e9ecef;">${taskLink}</td>
      <td style="padding:10px 12px;border-bottom:1px solid #e9ecef;text-align:center;">${task.fechaLimiteStr}</td>
      <td style="padding:10px 12px;border-bottom:1px solid #e9ecef;text-align:center;color:${daysColor};font-weight:bold;">${task.daysOverdue} dia(s)</td>
      <td style="padding:10px 12px;border-bottom:1px solid #e9ecef;text-align:center;"><span style="background:${priorityColor};color:white;padding:3px 10px;border-radius:12px;font-size:12px;">${task.prioridad}</span></td>
      <td style="padding:10px 12px;border-bottom:1px solid #e9ecef;text-align:center;">${task.estado}</td>
    </tr>`;
}

const criticalCount = tasks.filter(t => t.daysOverdue > 3).length;
const criticalBanner = criticalCount > 0
  ? `<div style="background:#fff3cd;border-left:4px solid #dc3545;padding:12px 16px;margin-bottom:20px;border-radius:4px;">
      <strong>Atencion:</strong> Tienes <strong>${criticalCount}</strong> tarea(s) con mas de 3 dias de atraso. Estas seran escaladas al equipo ejecutivo.
    </div>`
  : '';

const htmlBody = `
<!DOCTYPE html>
<html>
<head><meta charset="utf-8"></head>
<body style="font-family:'Segoe UI',Arial,sans-serif;background:#f4f6f9;margin:0;padding:20px;">
  <div style="max-width:700px;margin:0 auto;background:white;border-radius:8px;overflow:hidden;box-shadow:0 2px 8px rgba(0,0,0,0.08);">
    <div style="background:#1a1a2e;padding:24px 32px;">
      <h1 style="color:white;margin:0;font-size:22px;">Alerta de Tareas Vencidas</h1>
      <p style="color:#a0a0c0;margin:6px 0 0;font-size:14px;">FinteChile - Reporte Diario</p>
    </div>
    <div style="padding:24px 32px;">
      <p style="color:#333;font-size:15px;">Hola <strong>${asignado}</strong>,</p>
      <p style="color:#555;font-size:14px;">Tienes <strong>${totalTareas}</strong> tarea(s) vencida(s) que requieren tu atencion:</p>
      ${criticalBanner}
      <table style="width:100%;border-collapse:collapse;margin:16px 0;font-size:13px;">
        <thead>
          <tr style="background:#f8f9fa;">
            <th style="padding:10px 12px;text-align:left;border-bottom:2px solid #dee2e6;color:#495057;">Tarea</th>
            <th style="padding:10px 12px;text-align:center;border-bottom:2px solid #dee2e6;color:#495057;">Fecha Limite</th>
            <th style="padding:10px 12px;text-align:center;border-bottom:2px solid #dee2e6;color:#495057;">Dias Atraso</th>
            <th style="padding:10px 12px;text-align:center;border-bottom:2px solid #dee2e6;color:#495057;">Prioridad</th>
            <th style="padding:10px 12px;text-align:center;border-bottom:2px solid #dee2e6;color:#495057;">Estado</th>
          </tr>
        </thead>
        <tbody>
          ${tableRows}
        </tbody>
      </table>
      <p style="color:#555;font-size:14px;margin-top:20px;">Por favor, actualiza el estado de estas tareas en <a href="https://www.notion.so" style="color:#0366d6;">Notion</a> lo antes posible.</p>
    </div>
    <div style="background:#f8f9fa;padding:16px 32px;border-top:1px solid #e9ecef;">
      <p style="color:#999;font-size:12px;margin:0;">Este es un mensaje automatico generado por el sistema de gestion de tareas de FinteChile. No responder a este correo.</p>
    </div>
  </div>
</body>
</html>`;

const subject = `[FinteChile] Tienes ${totalTareas} tarea(s) vencida(s)${criticalCount > 0 ? ' - CRITICO' : ''}`;

return [{
  json: {
    asignado: item.asignado,
    asignadoEmail: item.asignadoEmail,
    totalTareas: item.totalTareas,
    tasks: item.tasks,
    hasCritical: item.hasCritical,
    emailSubject: subject,
    emailBody: htmlBody
  }
}];

// Recopilar TODAS las tareas criticas (>3 dias) de todos los items procesados
// Este nodo recibe el item actual que tiene hasCritical = true
const item = $input.first().json;
const tasks = item.tasks || [];
const criticalTasks = tasks.filter(t => t.daysOverdue > 3);

const today = new Date().toLocaleDateString('es-CL', {
  weekday: 'long',
  year: 'numeric',
  month: 'long',
  day: 'numeric'
});

let taskBlocks = '';
for (const task of criticalTasks) {
  const priorityEmoji = {
    'Urgente': ':rotating_light:',
    'Critica': ':rotating_light:',
    'Alta': ':red_circle:',
    'Media': ':large_orange_circle:',
    'Baja': ':large_green_circle:'
  }[task.prioridad] || ':white_circle:';

  const taskLink = task.taskUrl ? `<${task.taskUrl}|${task.taskName}>` : task.taskName;

  taskBlocks += `\n${priorityEmoji} *${taskLink}*\n    Responsable: *${item.asignado}* | Vencida: ${task.fechaLimiteStr} | *${task.daysOverdue} dias de atraso* | Prioridad: ${task.prioridad} | Estado: ${task.estado}\n`;
}

const slackMessage = `:warning: *ALERTA DE ESCALAMIENTO - Tareas Criticas Vencidas*\n_${today}_\n\n:bust_in_silhouette: *${item.asignado}* tiene ${criticalTasks.length} tarea(s) con mas de 3 dias de atraso:\n${taskBlocks}\n---\n:point_right: Se requiere atencion inmediata. Por favor, coordinar con el responsable para resolver estas tareas.`;

return [{
  json: {
    slackMessage,
    criticalCount: criticalTasks.length,
    asignado: item.asignado
  }
}];
